import{_ as e,o as l,c as a,ag as d}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Default Aliase | Dotfiles (DE)","titleTemplate":":title","description":"Wesentliche Shell-Aliase für Navigation, Systemsteuerung und tägliche Aufgaben. Vereinfachen Sie Ihren Terminal-Workflow mit diesen universellen Verknüpfungen.","frontmatter":{"title":"Default Aliase | Dotfiles","description":"Wesentliche Shell-Aliase für Navigation, Systemsteuerung und tägliche Aufgaben. Vereinfachen Sie Ihren Terminal-Workflow mit diesen universellen Verknüpfungen.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Default Aliase preview","canonical":"/de/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Default Aliase","pageType":"docs","schemaType":"WebPage","metaTitle":"Default Aliase - Dotfiles (DE)","permalink":"/de/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"default aliase, shell aliase, terminal verknüpfungen, dotfiles, bash aliase"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Wesentliche Shell-Aliase für Navigation, Systemsteuerung und tägliche Aufgaben."},{"name":"twitter:title","content":"Default Aliase - Dotfiles"},{"name":"og:title","content":"Default Aliase - Dotfiles"},{"name":"og:description","content":"Wesentliche Shell-Aliase für Navigation, Systemsteuerung und tägliche Aufgaben."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/aliases/default/index.md","filePath":"de/aliases/default/index.md","lastUpdated":1773010926000}'),n={name:"de/aliases/default/index.md"};function i(s,t,o,r,f,c){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="default-aliase" tabindex="-1">Default Aliase <a class="header-anchor" href="#default-aliase" aria-label="Permalink to &quot;Default Aliase&quot;">​</a></h1><p>Wesentliche Shell-Verknüpfungen für alltägliche Terminal-Aufgaben.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Diese Aliase sind in <code>default.aliases.sh</code> definiert und werden automatisch von Chezmoi geladen.</p><h2 id="referenz" tabindex="-1">Referenz <a class="header-anchor" href="#referenz" aria-label="Permalink to &quot;Referenz&quot;">​</a></h2><h3 id="allgemein" tabindex="-1">Allgemein <a class="header-anchor" href="#allgemein" aria-label="Permalink to &quot;Allgemein&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>da</code></td><td style="text-align:left;"><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td style="text-align:left;">Aktuelles Datum und Uhrzeit anzeigen</td></tr><tr><td style="text-align:left;"><code>p</code></td><td style="text-align:left;"><code>pwd</code></td><td style="text-align:left;">Arbeitsverzeichnis ausgeben</td></tr><tr><td style="text-align:left;"><code>path</code></td><td style="text-align:left;"><code>echo ${PATH//:/\\\\n}</code></td><td style="text-align:left;">PATH-Variable in neuen Zeilen anzeigen</td></tr><tr><td style="text-align:left;"><code>r</code></td><td style="text-align:left;"><code>reload</code></td><td style="text-align:left;">Shell neu laden</td></tr><tr><td style="text-align:left;"><code>t</code></td><td style="text-align:left;"><code>tail -f</code></td><td style="text-align:left;">Dateiausgabe in Echtzeit verfolgen</td></tr><tr><td style="text-align:left;"><code>wk</code></td><td style="text-align:left;"><code>date +%V</code></td><td style="text-align:left;">Aktuelle Kalenderwoche anzeigen</td></tr></tbody></table><h3 id="beenden-und-herunterfahren" tabindex="-1">Beenden und Herunterfahren <a class="header-anchor" href="#beenden-und-herunterfahren" aria-label="Permalink to &quot;Beenden und Herunterfahren&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>q</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">Shell beenden</td></tr><tr><td style="text-align:left;"><code>quit</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">Shell beenden</td></tr><tr><td style="text-align:left;"><code>bye</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">Shell beenden</td></tr><tr><td style="text-align:left;"><code>:q</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">Shell beenden (Vim-Stil)</td></tr><tr><td style="text-align:left;"><code>halt</code></td><td style="text-align:left;"><code>sudo /sbin/halt</code></td><td style="text-align:left;">System anhalten</td></tr><tr><td style="text-align:left;"><code>poweroff</code></td><td style="text-align:left;"><code>sudo /sbin/shutdown</code></td><td style="text-align:left;">System ausschalten</td></tr><tr><td style="text-align:left;"><code>reboot</code></td><td style="text-align:left;"><code>sudo /sbin/reboot</code></td><td style="text-align:left;">System neu starten</td></tr></tbody></table><h3 id="verlauf" tabindex="-1">Verlauf <a class="header-anchor" href="#verlauf" aria-label="Permalink to &quot;Verlauf&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>h</code></td><td style="text-align:left;"><code>history</code></td><td style="text-align:left;">Befehlsverlauf anzeigen</td></tr><tr><td style="text-align:left;"><code>history</code></td><td style="text-align:left;"><code>fc -il 1</code></td><td style="text-align:left;">Verlauf mit ISO 8601 Zeitstempeln anzeigen</td></tr></tbody></table><h3 id="netzwerk" tabindex="-1">Netzwerk <a class="header-anchor" href="#netzwerk" aria-label="Permalink to &quot;Netzwerk&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ifconfig</code></td><td style="text-align:left;"><code>sudo ifconfig</code></td><td style="text-align:left;">Netzwerkschnittstellen konfigurieren</td></tr><tr><td style="text-align:left;"><code>ipinfo</code></td><td style="text-align:left;"><code>ipconfig getpacket en0</code></td><td style="text-align:left;">Netzwerkparameter für en0 abrufen</td></tr><tr><td style="text-align:left;"><code>nls</code></td><td style="text-align:left;"><code>sudo lsof -i -P | grep LISTEN</code></td><td style="text-align:left;">Aktive Netzwerk-Listener anzeigen</td></tr><tr><td style="text-align:left;"><code>op</code></td><td style="text-align:left;"><code>sudo lsof -i -P</code></td><td style="text-align:left;">Offene Ports auflisten</td></tr><tr><td style="text-align:left;"><code>ping</code></td><td style="text-align:left;"><code>ping -c 5</code></td><td style="text-align:left;">Ping mit 5 Paket-Limit</td></tr><tr><td style="text-align:left;"><code>ports</code></td><td style="text-align:left;"><code>netstat -tulan</code></td><td style="text-align:left;">Alle lauschenden Ports auflisten</td></tr></tbody></table><h3 id="systemuberwachung" tabindex="-1">Systemüberwachung <a class="header-anchor" href="#systemuberwachung" aria-label="Permalink to &quot;Systemüberwachung&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>top</code></td><td style="text-align:left;"><code>sudo btop</code></td><td style="text-align:left;">Interaktiver Prozessmonitor</td></tr><tr><td style="text-align:left;"><code>spd</code></td><td style="text-align:left;"><code>sudo rm -rf /private/var/log/asl/*</code></td><td style="text-align:left;">ASL-Logdateien löschen</td></tr></tbody></table><h3 id="dienstprogramme" tabindex="-1">Dienstprogramme <a class="header-anchor" href="#dienstprogramme" aria-label="Permalink to &quot;Dienstprogramme&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ctf</code></td><td style="text-align:left;"><code>ls -1 | wc -l</code></td><td style="text-align:left;">Dateien im aktuellen Verzeichnis zählen</td></tr><tr><td style="text-align:left;"><code>qfind</code></td><td style="text-align:left;"><code>find . -name</code></td><td style="text-align:left;">Schnelle Dateisuche</td></tr><tr><td style="text-align:left;"><code>reload</code></td><td style="text-align:left;"><code>exec $SHELL -l</code></td><td style="text-align:left;">Shell neu laden</td></tr><tr><td style="text-align:left;"><code>wth</code></td><td style="text-align:left;"><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td style="text-align:left;">Aktuelles Wetter abrufen</td></tr></tbody></table>',17)])])}const u=e(n,[["render",i]]);export{g as __pageData,u as default};
